(()=>{'use strict';
const T=v=>String(v??'').trim();
const N=v=>Number(String(v??'').replace(/,/g,''))||0;
const $=s=>document.querySelector(s);
let busy=false;
function keys(prefix){const out=[];for(let i=0;i<localStorage.length;i++){const k=localStorage.key(i)||'';if(k.startsWith(prefix))out.push(k)}return out}
function read(k,d){try{return JSON.parse(localStorage.getItem(k)||'')||d}catch{return d}}
function write(k,v){localStorage.setItem(k,JSON.stringify(v||{}))}
function psKey(){const a=(window.DOIT_SELECTED_PS_KEY||'').trim();if(a)return a;return T($('#psSelect')?.value)}
function filter(){return{start:T($('#startDate')?.value),end:T($('#endDate')?.value),ps:psKey(),receiver:T($('#storeSelect')?.value)}}
function stateKeyFor(f){const stateKeys=keys('doit-json:');let fallback='';for(const sk of stateKeys){const st=read(sk,{});for(const mapName of ['send','add','pull']){const obj=st[mapName]||{};for(const k of Object.keys(obj)){const p=k.split('|');if(p[5]===f.receiver){fallback=sk;if((!f.start||p[0]===f.start)&&(!f.end||p[1]===f.end)&&(!f.ps||p[2]===f.ps))return sk}}}}return fallback||stateKeys[0]||''}
function suffix(sk){return sk.replace(/^doit-json:/,'')}
function rows(){return Array.isArray(window.__doitRawRows304)?window.__doitRawRows304:(Array.isArray(window.__doitAllRows)?window.__doitAllRows:[])}
function pkOf(r){return[T(r.brand),T(r.size),T(r.code||r.sku),T(r.sku),T(r.type||'INVC')].join('|')}
function groupMap(){const m=new Map();rows().forEach(r=>{const k=pkOf(r);let g=m.get(k);if(!g){g={code:T(r.code),name:T(r.sku),brand:T(r.brand),size:T(r.size),type:T(r.type||'INVC'),qty:0,amt:0,unit:N(r.unit)};m.set(k,g)}g.qty+=N(r.qty);g.amt+=N(r.amt);g.unit=g.qty&&g.amt?g.amt/g.qty:g.unit});return m}
function matchKey(k,f,strict=true){const p=String(k).split('|');if(p[5]!==f.receiver)return false;if(!strict)return true;if(f.start&&p[0]!==f.start)return false;if(f.end&&p[1]!==f.end)return false;if(f.ps&&p[2]!==f.ps)return false;return true}
function removeFromState(st,f){const removed=[],gm=groupMap();let strict=true;let any=false;for(const mapName of ['send','add','pull']){const obj=st[mapName]||{};if(Object.keys(obj).some(k=>matchKey(k,f,true)))any=true}if(!any)strict=false;for(const mapName of ['send','add','pull']){const obj=st[mapName]||{};Object.keys(obj).forEach(k=>{if(!matchKey(k,f,strict))return;const qty=N(obj[k]);const p=k.split('|');const pk=p.slice(6).join('|');const g=gm.get(pk)||{};removed.push({map:mapName,key:k,store:f.receiver,code:g.code||'',name:g.name||pk,brand:g.brand||'',size:g.size||'',type:g.type||'',qty,unit:N(g.unit)});delete obj[k]});st[mapName]=obj}return removed}
function removeManuals(sk,f){const mk='doit-manual-v1:'+suffix(sk),arr=read(mk,[]),keep=[],removed=[];let strict=arr.some(x=>x.store===f.receiver&&(!f.start||x.start===f.start)&&(!f.end||x.end===f.end)&&(!f.ps||x.ps===f.ps));arr.forEach(x=>{const hit=x.store===f.receiver&&(!strict||((!f.start||x.start===f.start)&&(!f.end||x.end===f.end)&&(!f.ps||x.ps===f.ps)));if(hit){removed.push({map:'manual',store:x.store,code:x.code||'',name:x.name,brand:x.brand||'เพิ่มเอง',size:x.size||'',type:x.type||'MANUAL',qty:N(x.qty),unit:N(x.unit),manual:true,id:x.id})}else keep.push(x)});localStorage.setItem(mk,JSON.stringify(keep));return removed}
function saveHistory(sk,f,items){const hk='doit-print-history-v1:'+suffix(sk);const h=read(hk,[]);h.unshift({at:new Date().toISOString(),store:f.receiver,start:f.start,end:f.end,ps:f.ps,items});localStorage.setItem(hk,JSON.stringify(h.slice(0,200)))}
function refresh(){try{document.body.classList.remove('printMode');$('#doitPrintOverlay')?.remove();window.DOIT_JSON_APP?.rerender?.();document.dispatchEvent(new CustomEvent('doit:stateChanged'))}catch(e){console.warn('[close-owner-v306] refresh failed',e)}}
function handle(id){if(busy)return;busy=true;setTimeout(()=>busy=false,1200);const saveHist=id!=='clearStoreBtn';const f=filter();if(!f.receiver){alert('กรุณาเลือกร้านจริงก่อนปิดบิลหรือล้างร้าน');return}const action=saveHist?'ปิดบิลและเก็บเข้า History':'ล้างรายการค้าง';if(!confirm(`${action}\nร้าน: ${f.receiver}\nวันที่: ${f.start||'ทุกวัน'} - ${f.end||'ทุกวัน'}\nPS: ${f.ps||'ทั้งหมด'}\n\nยืนยันดำเนินการ?`))return;const sk=stateKeyFor(f);if(!sk){alert('ยังไม่พบข้อมูลบันทึกของไฟล์นี้');return}const st=read(sk,{});const removed=[...removeFromState(st,f),...removeManuals(sk,f)];if(!removed.length){alert('ร้านนี้ไม่มีรายการค้างในช่วงวันที่/PS นี้');return}write(sk,st);if(saveHist){const histItems=removed.filter(x=>x.map==='send'||x.map==='manual').map(x=>({store:f.receiver,code:x.code||'',name:x.name,brand:x.brand,size:x.size,type:x.type,qty:N(x.qty),unit:N(x.unit),manual:!!x.manual,id:x.id}));saveHistory(sk,f,histItems)}alert(saveHist?`ปิดบิลแล้ว: ${f.receiver}`:`ล้างรายการแล้ว: ${f.receiver}`);refresh()}
function bind(){if(document.__closeOwner306)return;document.__closeOwner306=true;document.addEventListener('click',e=>{const id=e.target?.id;if(id==='doitConfirmPrint'||id==='closeBillBtn'||id==='clearStoreBtn'){e.preventDefault();e.stopImmediatePropagation();handle(id)}},true)}
bind();document.addEventListener('DOMContentLoaded',bind);
})();